import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../hooks/useAuth';
import { instructorAPI } from '../../api/client';
import s from './instructor.module.css';

/* ─── helpers ─────────────────────────────────────────────────────────────── */
const DAYS   = ['ПН','ВТ','СР','ЧТ','ПТ','СБ','ВС'];
const MONTHS = ['ЯНВАРЬ','ФЕВРАЛЬ','МАРТ','АПРЕЛЬ','МАЙ','ИЮНЬ',
                'ИЮЛЬ','АВГУСТ','СЕНТЯБРЬ','ОКТЯБРЬ','НОЯБРЬ','ДЕКАБРЬ'];

function getWeekDates(offset = 0) {
  const today  = new Date();
  const dow    = (today.getDay() + 6) % 7;
  const monday = new Date(today);
  monday.setDate(today.getDate() - dow + offset * 7);
  return Array.from({length:7}, (_,i) => {
    const d = new Date(monday); d.setDate(monday.getDate()+i); return d;
  });
}

const toISO = d => {
  // Используем локальную дату, не UTC
  const y = d.getFullYear();
  const m = String(d.getMonth()+1).padStart(2,'0');
  const day = String(d.getDate()).padStart(2,'0');
  return `${y}-${m}-${day}`;
};

const fmtRU = d => [
  String(d.getDate()).padStart(2,'0'),
  String(d.getMonth()+1).padStart(2,'0'),
  d.getFullYear(),
].join('.');

const initials = name =>
  name ? name.trim().split(/\s+/).map(w=>w[0]).join('').slice(0,2).toUpperCase() : '?';

/** Прибавить 90 минут к строке "HH:MM" */
function addNinety(timeStr) {
  const [h, m] = timeStr.split(':').map(Number);
  const total  = h * 60 + m + 90;
  return `${String(Math.floor(total/60)%24).padStart(2,'0')}:${String(total%60).padStart(2,'0')}`;
}

/** Является ли дата (ISO строка) прошедшей (строго до сегодня) */
function isPast(isoDate) {
  const today = toISO(new Date());
  return isoDate < today;
}

function Sp() { return <div className={s.spinner}/>; }

